#include <bits/stdc++.h>
using namespace std;
int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n; long long target;
    if (!(cin >> n >> target)) return 0;
    vector<long long> a(n);
    for (auto &x : a) cin >> x;
    unordered_map<long long, int> seen;
    for (int i = 0; i < n; ++i) {
        long long need = target - a[i];
        auto it = seen.find(need);
        if (it != seen.end()) {
            cout << it->second << ' ' << i << '\n';
            return 0;
        }
        if (!seen.count(a[i])) seen[a[i]] = i;
    }
    cout << "-1 -1\n";
    return 0;
}
